%[text] # 例2.6（グレースケール変換）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example2_06"; % mfilename

imgname = "msipimg02";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(im2double(imread(imgfile,imgfmt)),[96 96],'bilinear');

%%
%[text] ## 変換前の画像表示
figure(1) %[output:6aaed0cf]
imshow(X)  %[output:6aaed0cf]
title('原画像')  %[output:6aaed0cf]

imwrite(X,fullfile(resfolder,myfilename + "a.png"))

%%
[XR,XG,XB] = imsplit(X);
figure(2) %[output:482c115e]
hp = scatter3(XR(:),XG(:),XB(:),5,[XR(:) XG(:) XB(:)],'.'); %[output:482c115e]
axis equal %[output:482c115e]
set(gca,'XLim',[0 1]); %[output:482c115e]
set(gca,'YLim',[0 1]); %[output:482c115e]
set(gca,'ZLim',[0 1]); %[output:482c115e]
set(gca,'XTick',[0 0.2 0.4 0.6 0.8 1]); %[output:482c115e]
set(gca,'YTick',[0 0.2 0.4 0.6 0.8 1]); %[output:482c115e]
set(gca,'ZTick',[0 0.2 0.4 0.6 0.8 1]); %[output:482c115e]
xlabel('$x_\mathrm{R}$','Interpreter','latex') %[output:482c115e]
ylabel('$x_\mathrm{G}$','Interpreter','latex') %[output:482c115e]
zlabel('$x_\mathrm{B}$','Interpreter','latex') %[output:482c115e]
title('RGB空間')  %[output:482c115e]
ax = gca;
%view(ax,[2 1 1])
exportgraphics(ax,fullfile(resfolder,myfilename + "b.png")) %[output:482c115e]

%%
Y = imlincomb(0.299,XR,0.587,XG,0.114,XB);
figure(3) %[output:9bd5ee62]
imshow(Y) %[output:9bd5ee62]
title('グレースケール画像')  %[output:9bd5ee62]
%%
%[text] ## 結果出力
imwrite(Y,fullfile(resfolder,myfilename + "c.png"))

